defmodule SessionPlug do
  @moduledoc """
  Plug for integrating SessionManager with Phoenix.
  """

  import Plug.Conn
  @behaviour Plug

  @cookie_name "_app_session"
  @cookie_opts [
    http_only: true,
    secure: true,
    same_site: "Strict",
    max_age: 86_400,
    path: "/"
  ]

  @impl true
  def init(opts), do: opts

  @impl true
  def call(conn, _opts) do
    session_data =
      case get_cookie_session(conn) do
        {:ok, data} -> data
        {:error, _reason} -> %{}
      end

    conn
    |> assign(:session_data, session_data)
    |> register_before_send(&save_session/1)
  end

  defp get_cookie_session(conn) do
    conn = fetch_cookies(conn)

    case Map.get(conn.cookies, @cookie_name) do
      nil -> {:error, :no_session}
      cookie_value -> SessionManager.load_session(cookie_value)
    end
  end

  defp save_session(conn) do
    case Map.get(conn.assigns, :session_data) do
      nil ->
        conn

      data when is_map(data) ->
        cookie_value = SessionManager.create_session(data)
        put_resp_cookie(conn, @cookie_name, cookie_value, @cookie_opts)
    end
  end

  @doc """
  Helper to update session data in the connection assigns.
  """
  def put_session_value(conn, key, value) do
    current = Map.get(conn.assigns, :session_data, %{})
    updated = Map.put(current, key, value)
    assign(conn, :session_data, updated)
  end

  @doc """
  Helper to get a value from the session.
  """
  def get_session_value(conn, key, default \\ nil) do
    conn.assigns
    |> Map.get(:session_data, %{})
    |> Map.get(key, default)
  end

  @doc """
  Destroys the session by clearing session data and deleting the cookie.
  """
  def destroy_session(conn) do
    conn
    |> assign(:session_data, %{})
    |> delete_resp_cookie(@cookie_name, @cookie_opts)
  end
end